mapper.select:
SELECT t.id, t.track_id, t.person_id, t.person_name, t.longitude, t.latitude, t.altitude, t.speed, t.direction, t.accuracy, t.source_type, t.device_id, t.gps_time, t.location_type, t.location_desc, t.extra_data, t.create_time, t.update_time FROM person_track_point t INNER JOIN ( SELECT person_id, MAX(gps_time) AS max_time FROM person_track_point WHERE person_id IN
#{pid}
AND gps_time >= DATE_SUB(NOW(), INTERVAL #{minutes} MINUTE) AND deleted = 0 GROUP BY person_id ) latest ON t.person_id = latest.person_id AND t.gps_time = latest.max_time WHERE t.deleted = 0

