        #{item.altitude}, #{item.speed}, #{item.direction}, #{item.accuracy}, #{item.sourceType},
        #{item.deviceId}, #{item.gpsTime}, #{item.locationType}, #{item.locationDesc}, #{item.extraData}
    )

mapper.delete:
DELETE FROM person_track_point
WHERE gps_time < DATE_SUB(NOW(), INTERVAL #{days} DAY)
LIMIT #{limit}
